import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [availableTimes, setAvailableTimes] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  // ⭐ Feedback states
  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  // ✅ POPUP STATE
  const [popup, setPopup] = useState({ show: false, message: "" });

  // ================= GET DOCTOR =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  // ================= GET FEEDBACK =================
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  const avgRating =
    feedbacks.length > 0
      ? (
          feedbacks.reduce((sum, fb) => sum + fb.rating, 0) /
          feedbacks.length
        ).toFixed(1)
      : 0;

  // ================= DATE VALIDATION =================
  const getDayName = (dateStr) =>
    new Date(dateStr).toLocaleDateString("en-US", {
      weekday: "long",
    });

  const handleDateChange = (e) => {
    const selectedDate = e.target.value;
    const dayName = getDayName(selectedDate);

    if (!availableDays.includes(dayName)) {
      setPopup({
        show: true,
        message: `Doctor not available on ${dayName}`,
      });
      setDate("");
      return;
    }

    setDate(selectedDate);
  };

  // ================= BOOK APPOINTMENT =================
  const handleBooking = async () => {
    if (!date || !time) {
      setPopup({
        show: true,
        message: "Please select date and time",
      });
      return;
    }

    try {
      const res = await fetch("http://127.0.0.1:8000/book-appointment/", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Token ${localStorage.getItem("token")}`,
        },
        body: JSON.stringify({
          doctor_id,
          appointment_date: date,
          time_slot: time,
        }),
      });

      const data = await res.json();

      if (!res.ok) {
        setPopup({
          show: true,
          message: data.error || "Booking failed",
        });
        return;
      }

      setPopup({
        show: true,
        message: "Appointment booked successfully ✅",
      });

      setTimeout(() => {
        navigate("/my-appointments");
      }, 1500);

    } catch (err) {
      setPopup({
        show: true,
        message: "Server error ❌",
      });
    }
  };

  // ================= FEEDBACK =================
  const handleSubmitFeedback = () => {
    if (!rating || !comment) {
      setPopup({
        show: true,
        message: "Please add rating and comment",
      });
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
      });
  };

  if (!doctor) return <h2 style={styles.loading}>Loading...</h2>;

  return (
    <div style={styles.container}>
      <Navbar />

      {/* ================= POPUP ================= */}
      {popup.show && (
        <div style={styles.overlay}>
          <div style={styles.popupCard}>
            <h3>Notice</h3>
            <p>{popup.message}</p>
            <button
              style={styles.popupBtn}
              onClick={() => setPopup({ show: false, message: "" })}
            >
              OK
            </button>
          </div>
        </div>
      )}

      <div style={styles.main}>
        <div style={styles.card}>
          <div style={styles.left}>
            <img
              src={
                doctor.image ||
                "https://cdn-icons-png.flaticon.com/512/387/387561.png"
              }
              alt={doctor.name}
              style={styles.image}
            />
          </div>

          <div style={styles.right}>
            <h2>{doctor.name}</h2>
            <p><b>Specialization:</b> {doctor.field}</p>
            <p><b>Experience:</b> {doctor.experience}</p>
            <p><b>Qualification:</b> {doctor.qualification}</p>

            {/* ================= BOOKING ================= */}
            <div style={styles.bookingSection}>
              <label>Select Date:</label>
              <input
                type="date"
                value={date}
                onChange={handleDateChange}
                style={styles.input}
              />

              <label>Select Time:</label>
              <select
                value={time}
                onChange={(e) => setTime(e.target.value)}
                style={styles.input}
              >
                <option value="">Select Time</option>
                {availableTimes.map((t, i) => (
                  <option key={i}>{t}</option>
                ))}
              </select>

              <button style={styles.button} onClick={handleBooking}>
                Book Appointment
              </button>
            </div>

            {/* ================= FEEDBACK ================= */}
            <div style={styles.reviewContainer}>
              <h3>Patient Reviews</h3>

              <div style={styles.ratingSummary}>
                <h2>{avgRating} ⭐</h2>
                <p>{feedbacks.length} reviews</p>
              </div>

              <div style={styles.reviewForm}>
                <select
                  value={rating}
                  onChange={(e) => setRating(e.target.value)}
                  style={styles.input}
                >
                  <option value="">Select Rating</option>
                  <option value="5">⭐⭐⭐⭐⭐ Excellent</option>
                  <option value="4">⭐⭐⭐⭐ Good</option>
                  <option value="3">⭐⭐⭐ Average</option>
                  <option value="2">⭐⭐ Poor</option>
                  <option value="1">⭐ Bad</option>
                </select>

                <textarea
                  placeholder="Share your experience..."
                  value={comment}
                  onChange={(e) => setComment(e.target.value)}
                  style={styles.textarea}
                />

                <button onClick={handleSubmitFeedback} style={styles.submitBtn}>
                  Submit Review
                </button>
              </div>

              <div style={styles.reviewList}>
                {feedbacks.length > 0 ? (
                  feedbacks.map((fb) => (
                    <div key={fb.id} style={styles.reviewCard}>
                      <div style={styles.reviewHeader}>
                        👤 <b>{fb.user_name}</b>
                      </div>
                      <div>{"⭐".repeat(fb.rating)}</div>
                      <p>{fb.comment}</p>
                    </div>
                  ))
                ) : (
                  <p>No reviews yet</p>
                )}
              </div>
            </div>

          </div>
        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

